# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3

app = Flask(__name__)
web3 = Web3()

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    data = request.get_json()
    message = data['message']
    signature = data['signature']
    
    # Remove the "0x" prefix from the signature if present
    if signature.startswith("0x"):
        signature = signature[2:]
    
    # Recover the public address from the signature
    recovered_address = web3.eth.account.recoverMessage(message.encode('utf-8'), signature=signature)
    
    # Check if the recovered address matches the expected address
    expected_address = data.get('expected_address')
    if recovered_address == expected_address:
        return jsonify({'authenticated': True, 'address': recovered_address}), 200
    else:
        return jsonify({'authenticated': False, 'message': 'Invalid signature'}), 401

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)